const EF = `${SB}/functions/v1`
const aC=typeof window!=='undefined'?new(window.AudioContext||(window as any).webkitAudioContext)():null
function snd(t:string){if(!aC)return;try{aC.resume()}catch{};const o=aC.createOscillator(),g=aC.createGain();o.connect(g);g.connect(aC.destination);const n=aC.currentTime;g.gain.setValueAtTime(.1,n);if(t==='click'){o.frequency.setValueAtTime(600,n);g.gain.linearRampToValueAtTime(0,n+.05)}else if(t==='ok'){o.frequency.setValueAtTime(523,n);o.frequency.setValueAtTime(784,n+.15);g.gain.linearRampToValueAtTime(0,n+.3)}else if(t==='send'){o.frequency.setValueAtTime(880,n);o.frequency.linearRampToValueAtTime(1100,n+.08);g.gain.linearRampToValueAtTime(0,n+.1)}else if(t==='recv'){o.frequency.setValueAtTime(523,n);o.frequency.linearRampToValueAtTime(784,n+.2);g.gain.linearRampToValueAtTime(0,n+.25)}else if(t==='correct'){o.frequency.setValueAtTime(660,n);o.frequency.setValueAtTime(880,n+.1);g.gain.setValueAtTime(.15,n);g.gain.linearRampToValueAtTime(0,n+.2)}else if(t==='wrong'){o.frequency.setValueAtTime(200,n);o.type='sawtooth';g.gain.setValueAtTime(.08,n);g.gain.linearRampToValueAtTime(0,n+.2)}else if(t==='nav'){o.frequency.setValueAtTime(700,n);g.gain.setValueAtTime(.05,n);g.gain.linearRampToValueAtTime(0,n+.04)}else if(t==='badge'){o.frequency.setValueAtTime(523,n);o.frequency.setValueAtTime(659,n+.08);o.frequency.setValueAtTime(784,n+.16);o.frequency.setValueAtTime(1047,n+.24);g.gain.linearRampToValueAtTime(0,n+.4)};o.start(n);o.stop(n+.5)}
type Screen='loading'|'auth'|'confirm'|'reset'|'onboard'|'home'|'foxy'|'quiz'|'notes'|'progress'|'profile'
type Prof={name:string;grade:string;subject:string;language:string;studentId?:string}
type Stats={xp:number;streak:number;sessions:number;correct:number;asked:number;minutes:number}
type Note={id:string;title:string;content:string;note_type:string;color:string;chapter_number?:number;chapter_title?:string;is_pinned:boolean;is_starred:boolean;word_count:number;updated_at:string}
const GRADES=['Grade 6','Grade 7','Grade 8','Grade 9','Grade 10','Grade 11','Grade 12']
const SUBJ=[{id:'Mathematics',icon:'\u2211',c:'#E8590C'},{id:'Science',icon:'\u269B',c:'#0C8599'},{id:'English',icon:'Aa',c:'#7C3AED'},{id:'Hindi',icon:'\u0905',c:'#D97706'},{id:'Social Studies',icon:'\uD83C\uDF0D',c:'#059669'},{id:'Physics',icon:'\u26A1',c:'#2563EB'},{id:'Chemistry',icon:'\uD83E\uDDEA',c:'#DC2626'},{id:'Biology',icon:'\uD83E\uDDEC',c:'#16A34A'},{id:'Computer Science',icon:'\uD83D\uDCBB',c:'#0D9488'},{id:'Accountancy',icon:'\uD83D\uDCCA',c:'#7C3AED'},{id:'Economics',icon:'\uD83D\uDCC8',c:'#D97706'}]
const LANGS=[{code:'en',label:'English'},{code:'hi',label:'Hindi'},{code:'ta',label:'Tamil'},{code:'te',label:'Telugu'},{code:'bn',label:'Bengali'},{code:'mr',label:'Marathi'}]
const NC=['#E8590C','#2563EB','#7C3AED','#D97706','#059669','#DC2626','#0D9488','#EC4899']
const SM:Record<string,string>={Mathematics:'math',Science:'science',English:'english',Hindi:'hindi','Social Studies':'social_studies',Physics:'physics',Chemistry:'chemistry',Biology:'biology','Computer Science':'computer_science'}
// API helpers
async function api(fn:string,body:any){try{const r=await fetch(`${EF}/${fn}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});return await r.json()}catch{return{error:'API failed'}}}
async function ensureStudent(uid:string,p:Prof):Promise<string|null>{try{const{data:ex}=await sb.from('students').select('id').eq('auth_user_id',uid).maybeSingle();if(ex){await sb.from('students').update({name:p.name,grade:p.grade,preferred_language:p.language,onboarding_completed:true}).eq('id',ex.id);return ex.id};const{data:cr}=await sb.from('students').insert({auth_user_id:uid,name:p.name,grade:p.grade,preferred_language:p.language,onboarding_completed:true}).select('id').single();return cr?.id||null}catch(e){console.error(e);return null}}
async function getStats(sid:string):Promise<Stats>{const z:Stats={xp:0,streak:0,sessions:0,correct:0,asked:0,minutes:0};if(!sid)return z;try{const{data}=await sb.from('student_overall_stats').select('total_xp,streak_days,total_sessions,total_questions_asked,total_questions_answered_correctly,total_time_minutes').eq('student_id',sid).maybeSingle();if(!data)return z;return{xp:data.total_xp||0,streak:data.streak_days||0,sessions:data.total_sessions||0,correct:data.total_questions_answered_correctly||0,asked:data.total_questions_asked||0,minutes:data.total_time_minutes||0}}catch{return z}}
async function getTopicMastery(sid:string,sub:string){try{const{data}=await sb.from('topic_mastery').select('topic_tag,mastery_percent,mastery_level,total_attempts,correct_attempts').eq('student_id',sid).eq('subject',sub).order('mastery_percent',{ascending:false}).limit(20);return data||[]}catch{return[]}}
// AUTH
function Auth({onAuth,onConfirm}:{onAuth:(u:any)=>void;onConfirm:()=>void}){const[mode,setMode]=useState<'login'|'signup'|'forgot'>('login');const[email,setEmail]=useState('');const[pw,setPw]=useState('');const[nm,setNm]=useState('');const[ld,setLd]=useState(false);const[err,setErr]=useState('');const[msg,setMsg]=useState('');const ggl=async()=>{const{error}=await sb.auth.signInWithOAuth({provider:'google',options:{redirectTo:SITE}});if(error)setErr(error.message)};const go=async()=>{setErr('');setMsg('');setLd(true);try{if(mode==='forgot'){const{error}=await sb.auth.resetPasswordForEmail(email,{redirectTo:`${SITE}?reset=true`});if(error)throw error;setMsg('Reset link sent!');setLd(false);return}if(pw.length<6)throw new Error('6+ chars');if(mode==='signup'){if(!nm.trim())throw new Error('Name required');const{data,error}=await sb.auth.signUp({email,password:pw,options:{data:{full_name:nm},emailRedirectTo:SITE}});if(error)throw error;if(!data.session){snd('ok');onConfirm();setLd(false);return}snd('ok');onAuth(data.user)}else{const{data,error}=await sb.auth.signInWithPassword({email,password:pw});if(error)throw error;snd('ok');onAuth(data.user)}}catch(e:any){snd('click');setErr(e.message?.includes('Invalid')?'Wrong email or password':e.message||'Error')};setLd(false)};return(<div className="a-auth"><div className="a-auth-l"><div style={{fontSize:56}}>&#x1F98A;</div><h1>Alfanumrik</h1><p style={{fontSize:16,color:'rgba(255,255,255,.5)',marginTop:8}}>AI-powered adaptive learning by CusioSense Learning India Private Limited</p></div><div className="a-auth-r"><div style={{width:'100%',maxWidth:400}}><h2 style={{fontSize:28,fontWeight:800,marginBottom:24}}>{mode==='forgot'?'Reset password':mode==='signup'?'Create account':'Welcome back'}</h2>{mode!=='forgot'&&<div className="a-tabs">{(['login','signup']as const).map(m=><button key={m} onClick={()=>{setMode(m);setErr('');setMsg('')}} className={`a-tab${mode===m?' on':''}`}>{m==='login'?'Log In':'Sign Up'}</button>)}</div>}{err&&<div className="a-err">{err}</div>}{msg&&<div className="a-ok">{msg}</div>}{mode==='signup'&&<input value={nm} onChange={e=>setNm(e.target.value)} placeholder="Full name" className="a-inp"/>}<input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="Email" className="a-inp"/>{mode!=='forgot'&&<input type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder="Password" className="a-inp" onKeyDown={e=>e.key==='Enter'&&go()}/>}<button onClick={go} disabled={ld} className="a-btn">{ld?'Please wait...':{login:'Log In',signup:'Create Account',forgot:'Send Reset Link'}[mode]}</button>{mode==='login'&&<button onClick={()=>setMode('forgot')} className="a-link">Forgot password?</button>}{mode==='forgot'&&<button onClick={()=>setMode('login')} className="a-link">Back to login</button>}{mode!=='forgot'&&<><div className="a-divider"><span>or</span></div><button onClick={ggl} className="a-ggl"><svg width="18" height="18" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59A14.5 14.5 0 019.5 24c0-1.59.28-3.14.77-4.59l-7.98-6.19A23.9 23.9 0 000 24c0 3.87.93 7.52 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.15 1.45-4.92 2.3-8.16 2.3-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/></svg>Continue with Google</button></>}</div></div></div>)}
function ConfirmScreen({onBack}:{onBack:()=>void}){return(<div className="a-center-dark"><div style={{fontSize:64,marginBottom:16}}>&#x2709;&#xFE0F;</div><h2 style={{fontSize:24,fontWeight:800,color:'#fff',marginBottom:8}}>Check your email!</h2><p style={{fontSize:15,color:'rgba(255,255,255,.6)',marginBottom:24}}>Click the verification link to activate your account.</p><button onClick={onBack} className="a-btn" style={{maxWidth:200}}>Back to Login</button></div>)}
function ResetScreen(){const[pw,setPw]=useState('');const[pw2,setPw2]=useState('');const[ld,setLd]=useState(false);const[msg,setMsg]=useState('');const[err,setErr]=useState('');const go=async()=>{if(pw.length<6||pw!==pw2){setErr("Passwords don't match or too short");return}setLd(true);const{error}=await sb.auth.updateUser({password:pw});if(error)setErr(error.message);else{setMsg('Updated! Redirecting...');setTimeout(()=>window.location.href=SITE,2000)}setLd(false)};return(<div className="a-center-dark"><div style={{fontSize:48}}>&#x1F510;</div><h2 style={{fontSize:22,fontWeight:800,color:'#fff',margin:'12px 0 24px'}}>Set new password</h2>{err&&<div className="a-err">{err}</div>}{msg&&<div className="a-ok">{msg}</div>}<input type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder="New password" className="a-inp" style={{background:'rgba(255,255,255,.06)',color:'#fff',borderColor:'rgba(255,255,255,.1)'}}/><input type="password" value={pw2} onChange={e=>setPw2(e.target.value)} placeholder="Confirm" className="a-inp" style={{background:'rgba(255,255,255,.06)',color:'#fff',borderColor:'rgba(255,255,255,.1)'}} onKeyDown={e=>e.key==='Enter'&&go()}/><button onClick={go} disabled={ld} className="a-btn">{ld?'Updating...':'Update Password'}</button></div>)}
function Onboard({user,done}:{user:any;done:(p:Prof)=>void}){const[s,setS]=useState(0);const[nm,setNm]=useState(user?.user_metadata?.full_name||'');const[gr,setGr]=useState('');const[su,setSu]=useState('');const[la,setLa]=useState('en');const ok=[!!nm.trim(),!!gr,!!su,true][s];const nx=()=>{snd('click');setS(v=>v+1)};return(<div className="a-center-dark" style={{maxWidth:480,padding:'40px 24px'}}><div style={{display:'flex',gap:6,justifyContent:'center',marginBottom:32}}>{[0,1,2,3].map(i=><div key={i} style={{height:8,borderRadius:4,background:i<=s?'#E8590C':'rgba(255,255,255,.15)',width:i<=s?24:8}}/>)}</div><div style={{fontSize:56,marginBottom:16}}>&#x1F98A;</div><h2 style={{fontSize:26,fontWeight:800,color:'#fff',marginBottom:28}}>{['What should Foxy call you?','Which grade?','Pick a subject','Choose language'][s]}</h2><div key={s} style={{animation:'slideUp .25s',minHeight:160}}>{s===0&&<input value={nm} onChange={e=>setNm(e.target.value)} placeholder="Your name" autoFocus className="a-ob-inp" onKeyDown={e=>e.key==='Enter'&&nm.trim()&&nx()}/>}{s===1&&<div className="a-ob-g3">{GRADES.map(g=><button key={g} onClick={()=>{setGr(g);snd('click')}} className={`a-ob-ch${gr===g?' on':''}`}>{g}</button>)}</div>}{s===2&&<div className="a-ob-g2">{SUBJ.filter(x=>{const g=parseInt(gr.replace(/\D/g,'')||'6');return g>=11?['Mathematics','Physics','Chemistry','Biology','English','Computer Science','Accountancy','Economics'].includes(x.id):['Mathematics','Science','English','Hindi','Social Studies'].includes(x.id)}).map(x=><button key={x.id} onClick={()=>{setSu(x.id);snd('click')}} className={`a-ob-ch${su===x.id?' on':''}`} style={su===x.id?{background:x.c}:{}}><span style={{fontSize:18}}>{x.icon}</span>{x.id}</button>)}</div>}{s===3&&<div className="a-ob-g2">{LANGS.map(l=><button key={l.code} onClick={()=>{setLa(l.code);snd('click')}} className={`a-ob-ch${la===l.code?' on':''}`}>{l.label}</button>)}</div>}</div><div style={{display:'flex',gap:10,marginTop:28}}>{s>0&&<button onClick={()=>{setS(v=>v-1)}} className="a-ob-back">Back</button>}<button onClick={s<3?nx:()=>{snd('ok');done({name:nm.trim(),grade:gr,subject:su,language:la})}} disabled={!ok} className="a-ob-next">{s<3?'Continue':"Let's Go!"}</button></div></div>)}
// HOME with PWA install + quiz history
function Home({p,nav,stats,history}:{p:Prof;nav:(s:Screen)=>void;stats:Stats;history:any}){const h=new Date().getHours();const gr=h<12?'Good morning':h<17?'Good afternoon':'Good evening';const[inst,setInst]=useState(false);useEffect(()=>{if(typeof window!=='undefined'&&(window as any).alfanumrikInstallPrompt)setInst(true)},[]);const doInst=async()=>{const pr=(window as any).alfanumrikInstallPrompt;if(pr){pr.prompt();const{outcome}=await pr.userChoice;if(outcome==='accepted')setInst(false)}};return(<div className="a-page"><div className="a-hdr"><div><p className="a-greet">{gr}</p><h1 className="a-title">{p.name}</h1></div><div className="a-badge">{p.grade} &middot; {p.subject}</div></div>{inst&&<button onClick={doInst} className="a-install">{'\uD83D\uDCF2'} Install Alfanumrik App</button>}<div className="a-home-grid"><div className="a-daily"><span className="a-daily-tag">QUICK ACCESS</span>{[{i:'\uD83E\uDD8A',l:'Continue with Foxy',s:'Resume your conversation',sc:'foxy' as Screen},{i:'\uD83C\uDFAF',l:'Take a Quiz',s:'Custom chapter & count',sc:'quiz' as Screen},{i:'\uD83D\uDDD2\uFE0F',l:'My Notes',s:`${history?.notes?.length||0} revision notes`,sc:'notes' as Screen}].map((a,i)=><button key={i} onClick={()=>{snd('click');nav(a.sc)}} className="a-daily-row"><div className="a-daily-ic">{a.i}</div><div style={{flex:1,textAlign:'left'}}><p style={{fontSize:14,fontWeight:700,color:'#fff'}}>{a.l}</p><p style={{fontSize:12,color:'rgba(255,255,255,.4)'}}>{a.s}</p></div><span style={{color:'rgba(255,255,255,.25)',fontSize:20}}>&rsaquo;</span></button>)}<button onClick={()=>{snd('ok');nav('foxy')}} className="a-daily-go">Start Learning</button></div><div className="a-home-r"><div className="a-stats">{[{v:String(stats.xp),l:'XP',i:'\u26A1'},{v:String(stats.sessions),l:'Quizzes',i:'\u2705'},{v:stats.asked>0?Math.round((stats.correct/stats.asked)*100)+'%':'0%',l:'Accuracy',i:'\uD83C\uDFAF'},{v:String(stats.streak),l:'Streak',i:'\uD83D\uDD25'},{v:String(stats.minutes),l:'Minutes',i:'\u23F1'},{v:String(stats.asked),l:'Questions',i:'\u2753'}].map(x=>(<div key={x.l} className="a-stat"><span style={{fontSize:18}}>{x.i}</span><p className="a-stat-v">{x.v}</p><p className="a-stat-l">{x.l}</p></div>))}</div>{/* Recent quiz history */}{history?.quizzes?.length>0&&<div className="a-card"><h3 className="a-card-t">RECENT QUIZZES</h3>{history.quizzes.slice(0,4).map((q:any)=><div key={q.id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'8px 0',borderBottom:'1px solid #F5F4F0'}}><div><p style={{fontSize:13,fontWeight:600}}>{q.subject} &middot; {q.grade}</p><p style={{fontSize:11,color:'#A8A29E'}}>{new Date(q.created_at).toLocaleDateString('en-IN',{day:'numeric',month:'short'})}</p></div><div style={{fontSize:14,fontWeight:800,color:q.score_percent>=70?'#16A34A':q.score_percent>=40?'#D97706':'#DC2626'}}>{q.score_percent}%</div></div>)}</div>}</div></div></div>)}
// FOXY CHAT with PERSISTENT HISTORY — loads from DB, saves every message, continues across refreshes
function Foxy({p}:{p:Prof}){const subCode=SM[p.subject]||'math';const[msgs,setMsgs]=useState<any[]>([]);const[inp,setInp]=useState('');const[ld,setLd]=useState(false);const[initLd,setInitLd]=useState(true);const[hist,setHist]=useState<any[]>([]);const[spk,setSpk]=useState<number|null>(null);const[sesId,setSesId]=useState<string|null>(null);const end=useRef<HTMLDivElement>(null);const iR=useRef<HTMLInputElement>(null);
// Load chat session on mount
useEffect(()=>{(async()=>{if(!p.studentId)return;const r=await api('chat-history',{action:'get_or_create',student_id:p.studentId,subject:subCode,grade:p.grade});if(r.session){setSesId(r.session.id);const savedMsgs=r.session.messages||[];if(savedMsgs.length>0){setMsgs(savedMsgs);const h=savedMsgs.filter((m:any)=>!m.isSystem).map((m:any)=>({role:m.isUser?'user':'assistant',content:m.text}));setHist(h)}else{setMsgs([{id:1,text:`Hey ${p.name}! I'm Foxy, your ${p.subject} tutor for ${p.grade}. Ask me anything!`,isUser:false,ts:Date.now()}])}}setInitLd(false)})()},[p.studentId,p.subject]);
useEffect(()=>{end.current?.scrollIntoView({behavior:'smooth'})},[msgs]);
// Save messages to DB after every change
const saveToDb=useCallback(async(newMsgs:any[],sid:string|null)=>{if(!p.studentId||!sid||newMsgs.length<=1)return;await api('chat-history',{action:'save_messages',student_id:p.studentId,session_id:sid,messages:newMsgs,title:newMsgs.find((m:any)=>m.isUser)?.text?.substring(0,40)||'Chat'})},[p.studentId]);
const speak=async(id:number,t:string)=>{if(spk===id){setSpk(null);return}setSpk(id);await api('tts-voice',{text:t.replace(/<svg[\s\S]*?<\/svg>/gi,'').substring(0,500),language:p.language,speed:'fast'}).then(d=>{if(d.audio_url)new Audio(d.audio_url).play()});setSpk(null)};
const renderMsg=(t:string)=>{if(!t?.includes('<svg'))return t||'';const parts=t.split(/(<svg[\s\S]*?<\/svg>)/gi);return <>{parts.map((pt,i)=>pt.startsWith('<svg')?<div key={i} style={{margin:'8px 0',maxWidth:400}} dangerouslySetInnerHTML={{__html:pt}}/>:<span key={i}>{pt}</span>)}</>};
const saveNote=async(text:string)=>{if(!p.studentId)return;await api('student-notes',{action:'create',student_id:p.studentId,subject:subCode,grade:p.grade,title:'Foxy: '+text.substring(0,40)+'...',content:text.replace(/<svg[\s\S]*?<\/svg>/gi,''),note_type:'summary',source:'foxy_chat',color:'#E8590C'});snd('ok')};
const newChat=async()=>{if(!p.studentId)return;const r=await api('chat-history',{action:'new_chat',student_id:p.studentId,subject:subCode,grade:p.grade});if(r.session){setSesId(r.session.id);setMsgs([{id:Date.now(),text:`Fresh start! What would you like to learn, ${p.name}?`,isUser:false,ts:Date.now()}]);setHist([]);snd('ok')}};
const send=async(t:string)=>{if(!t.trim()||ld)return;const m=t.trim();snd('send');const userMsg={id:Date.now(),text:m,isUser:true,ts:Date.now()};const newMsgs=[...msgs,userMsg];setMsgs(newMsgs);setInp('');setLd(true);const nh=[...hist,{role:'user',content:m}];const res=await api('foxy-tutor',{messages:nh,student_name:p.name,grade:p.grade,subject:p.subject,language:p.language,student_id:p.studentId||null});snd('recv');const botMsg={id:Date.now()+1,text:res.text||'Foxy had a hiccup!',isUser:false,ts:Date.now()};const allMsgs=[...newMsgs,botMsg];setMsgs(allMsgs);setHist([...nh,{role:'assistant',content:res.text}]);saveToDb(allMsgs,sesId);setLd(false);iR.current?.focus()};
if(initLd)return<div className="a-center" style={{background:'#fff'}}><div style={{fontSize:48,animation:'pulse 1.5s infinite'}}>&#x1F98A;</div><p style={{color:'#A8A29E',marginTop:8}}>Loading your conversation...</p></div>;
return(<div className="a-chat"><div className="a-chat-hdr"><div className="a-chat-av">&#x1F98A;</div><div style={{flex:1}}><p style={{fontSize:15,fontWeight:700}}>Foxy &mdash; {p.subject}</p><p style={{fontSize:12,color:'#A8A29E'}}>{msgs.length-1} messages &middot; {p.grade}</p></div><button onClick={newChat} style={{padding:'6px 12px',borderRadius:8,border:'1px solid #E7E5E4',background:'#fff',fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'inherit',color:'#57534E'}}>+ New Chat</button></div><div className="a-chat-body">{msgs.map(m=>(<div key={m.id} className={`a-msg ${m.isUser?'u':'b'}`}>{!m.isUser&&<div className="a-msg-av">&#x1F98A;</div>}<div><div className={`a-bub ${m.isUser?'u':'b'}`}>{m.isUser?m.text:renderMsg(m.text)}</div>{!m.isUser&&m.id!==1&&<div style={{display:'flex',gap:6,marginTop:4}}><button onClick={()=>speak(m.id,m.text)} className="a-speak-btn">{spk===m.id?'\uD83D\uDD0A':'\uD83D\uDD08'}</button><button onClick={()=>saveNote(m.text)} className="a-speak-btn">{'\uD83D\uDDD2\uFE0F'}</button></div>}</div></div>))}{ld&&<div className="a-msg b"><div className="a-msg-av">&#x1F98A;</div><div className="a-typing"><span/><span/><span/></div></div>}<div ref={end}/></div>{msgs.length<=2&&<div className="a-chips">{['Explain a concept','Draw a diagram','Give me a question','Quiz me','Revise last topic'].map(c=><button key={c} onClick={()=>send(c)} className="a-chip">{c}</button>)}</div>}<div className="a-chat-bar"><input ref={iR} value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==='Enter'&&send(inp)} placeholder="Ask Foxy anything..." className="a-chat-inp"/><button onClick={()=>send(inp)} disabled={!inp.trim()||ld} className="a-chat-go">{'\u2191'}</button></div></div>)}
// QUIZ
function Quiz({p,onDone}:{p:Prof;onDone:()=>void}){const[phase,setPhase]=useState<'setup'|'play'|'done'>('setup');const[qs,setQs]=useState<any[]>([]);const[ci,setCi]=useState(0);const[sel,setSel]=useState<number|null>(null);const[score,setScore]=useState(0);const[rev,setRev]=useState(false);const[sesId,setSesId]=useState<string|null>(null);const[resps,setResps]=useState<any[]>([]);const[result,setResult]=useState<any>(null);const[qStart,setQStart]=useState(Date.now());const[qzStart,setQzStart]=useState(Date.now());const[ld,setLd]=useState(false);const[chs,setChs]=useState<any[]>([]);const[selCh,setSelCh]=useState<number|null>(null);const[selN,setSelN]=useState(10);useEffect(()=>{(async()=>{const d=await api('quiz-engine',{subject:p.subject,grade:p.grade,count:0,student_id:p.studentId});setChs(d.chapters||[])})()},[p.grade,p.subject]);const start=async()=>{setLd(true);const d=await api('quiz-engine',{subject:p.subject,grade:p.grade,count:selN,student_id:p.studentId,chapter_number:selCh||undefined});setQs(d.questions||[]);setSesId(d.session_id||null);setLd(false);if(d.questions?.length){setPhase('play');setQStart(Date.now());setQzStart(Date.now())}};const pick=(i:number)=>{if(rev)return;setSel(i);setRev(true);const q=qs[ci];const ok=i===q.correct_answer_index;if(ok){setScore(s=>s+1);snd('correct')}else snd('wrong');setResps(v=>[...v,{question_number:ci+1,question_text:q.question_text,question_type:'mcq',options:q.options,correct_answer_index:q.correct_answer_index,correct_answer_text:q.options?.[q.correct_answer_index]||'',student_answer_index:i,student_answer_text:q.options?.[i]||'',is_correct:ok,time_taken_seconds:Math.round((Date.now()-qStart)/1000),marks:1,explanation:q.explanation||'',topic_tag:q.topic_tag||'general',bloom_level:q.bloom_level||'understand',difficulty:q.difficulty||2,subject:p.subject,grade:p.grade}])};const next=async()=>{if(ci<qs.length-1){setCi(v=>v+1);setSel(null);setRev(false);snd('click');setQStart(Date.now())}else{setPhase('done');snd('badge');if(p.studentId){const r=await api('quiz-submit',{session_id:sesId,student_id:p.studentId,responses:resps,total_time_seconds:Math.round((Date.now()-qzStart)/1000)});setResult(r);if(r.success)onDone()}}};const reset=()=>{setPhase('setup');setCi(0);setSel(null);setRev(false);setScore(0);setResps([]);setResult(null);setQs([])};
if(phase==='setup')return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Custom Quiz</h1><p className="a-greet">{p.subject} &middot; {p.grade}</p></div></div><div className="a-card" style={{maxWidth:600}}><h3 className="a-card-t">CONFIGURE YOUR QUIZ</h3><label className="a-label">Chapter</label><div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:16}}><button onClick={()=>setSelCh(null)} className={`a-pill${!selCh?' on':''}`}>All</button>{chs.map(c=><button key={c.chapter} onClick={()=>{setSelCh(c.chapter);snd('click')}} className={`a-pill${selCh===c.chapter?' on':''}`}>Ch{c.chapter}: {c.title?.substring(0,18)}</button>)}</div><label className="a-label">Questions</label><div style={{display:'flex',gap:8,marginBottom:16}}>{[5,10,15,20,25].map(n=><button key={n} onClick={()=>{setSelN(n);snd('click')}} className={`a-pill-n${selN===n?' on':''}`}>{n}</button>)}</div><button onClick={start} disabled={ld} className="a-daily-go">{ld?'Generating...':'Start Quiz'}</button></div></div>);
if(phase==='done'){const pct=qs.length?Math.round((score/qs.length)*100):0;return<div className="a-page" style={{textAlign:'center',paddingTop:40}}><div style={{fontSize:64,marginBottom:12}}>{pct>=80?'\uD83C\uDF89':pct>=50?'\uD83D\uDC4D':'\uD83D\uDCAA'}</div><h2 style={{fontSize:28,fontWeight:900}}>Quiz Complete!</h2><p style={{color:'#A8A29E',margin:'8px 0 20px'}}>{score}/{qs.length} ({pct}%){result?.xp_earned?' \u2022 +'+result.xp_earned+' XP':''}</p>{result?.topic_mastery?.length>0&&<div className="a-card" style={{maxWidth:400,margin:'0 auto 20px',textAlign:'left'}}><h3 className="a-card-t">MASTERY UPDATE</h3>{result.topic_mastery.map((t:any,i:number)=><div key={i} style={{marginBottom:8}}><div style={{display:'flex',justifyContent:'space-between'}}><span style={{fontSize:13,fontWeight:600}}>{t.topic?.replace(/_/g,' ')}</span><span style={{fontSize:12,fontWeight:700,color:t.mastery>=70?'#16A34A':'#D97706'}}>{t.mastery}%</span></div><div style={{height:5,borderRadius:3,background:'#F5F4F0'}}><div style={{height:'100%',borderRadius:3,width:`${t.mastery}%`,background:t.mastery>=70?'#16A34A':t.mastery>=40?'#D97706':'#DC2626'}}/></div></div>)}</div>}<button onClick={reset} className="a-daily-go" style={{maxWidth:300,margin:'0 auto',display:'block'}}>Another Quiz</button></div>}
const q=qs[ci];if(!q)return<div className="a-page" style={{textAlign:'center',paddingTop:80}}><p style={{fontSize:48}}>&#x1F614;</p><button onClick={reset} className="a-daily-go" style={{maxWidth:200,margin:'20px auto'}}>Back</button></div>;
return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Quiz</h1><p className="a-greet">{q.topic_tag?.replace(/_/g,' ')}</p></div><div className="a-badge">Q{ci+1}/{qs.length}</div></div><div className="a-card" style={{maxWidth:700}}><div style={{display:'flex',gap:3,marginBottom:16}}>{qs.map((_:any,i:number)=><div key={i} style={{flex:1,height:4,borderRadius:2,background:i<ci?(resps[i]?.is_correct?'#16A34A':'#DC2626'):i===ci?'#E8590C':'#EDEBE6'}}/>)}</div><h3 style={{fontSize:17,fontWeight:700,marginBottom:18,lineHeight:1.5}}>{q.question_text}</h3><div style={{display:'flex',flexDirection:'column',gap:8}}>{(q.options as string[]).map((opt:string,idx:number)=>{let bg='#fff',bd='1px solid #E7E5E4',cl='#1C1917';if(rev&&idx===q.correct_answer_index){bg='#DCFCE7';bd='1.5px solid #16A34A';cl='#15803D'}else if(rev&&idx===sel&&idx!==q.correct_answer_index){bg='#FEE2E2';bd='1.5px solid #DC2626';cl='#B91C1C'}else if(idx===sel){bg='#FFF7ED';bd='1.5px solid #E8590C';cl='#E8590C'};return<button key={idx} onClick={()=>pick(idx)} style={{padding:'12px 14px',borderRadius:12,background:bg,border:bd,color:cl,fontSize:14,fontWeight:600,textAlign:'left',cursor:rev?'default':'pointer',fontFamily:'inherit'}}>{String.fromCharCode(65+idx)}. {opt}</button>})}</div>{rev&&<div style={{marginTop:14,padding:12,borderRadius:12,background:'#F5F4F0'}}><p style={{fontSize:13,fontWeight:700,color:sel===q.correct_answer_index?'#16A34A':'#DC2626',marginBottom:4}}>{sel===q.correct_answer_index?'Correct!':'Not quite'}</p>{q.explanation&&<p style={{fontSize:13,color:'#57534E',lineHeight:1.5}}>{q.explanation}</p>}</div>}{rev&&<button onClick={next} className="a-daily-go" style={{marginTop:14}}>{ci<qs.length-1?'Next':'Finish'}</button>}</div></div>)}
// NOTES
function Notes({p}:{p:Prof}){const subCode=SM[p.subject]||'math';const[notes,setNotes]=useState<Note[]>([]);const[ld,setLd]=useState(true);const[view,setView]=useState<'grid'|'edit'>('grid');const[editNote,setEditNote]=useState<Note|null>(null);const[title,setTitle]=useState('');const[content,setContent]=useState('');const[noteType,setNoteType]=useState('manual');const[noteColor,setNoteColor]=useState('#E8590C');const[genLd,setGenLd]=useState(false);const[chs,setChs]=useState<any[]>([]);const[filterCh,setFilterCh]=useState<number|null>(null);const[expanded,setExpanded]=useState<string|null>(null);
useEffect(()=>{loadNotes();loadChs()},[p.studentId,p.subject]);
const loadNotes=async()=>{if(!p.studentId)return;setLd(true);const r=await api('student-notes',{action:'list',student_id:p.studentId,subject:subCode,chapter_number:filterCh||undefined});setNotes(r.notes||[]);setLd(false)};
const loadChs=async()=>{try{const{data:s}=await sb.from('subjects').select('id').eq('code',subCode).single();if(!s)return;const{data}=await sb.from('curriculum_topics').select('chapter_number,title').eq('subject_id',s.id).eq('grade',p.grade).eq('is_active',true).order('chapter_number');setChs(data||[])}catch{}};
useEffect(()=>{if(p.studentId)loadNotes()},[filterCh]);
const saveNote=async()=>{if(!p.studentId||!title.trim())return;if(editNote){await api('student-notes',{action:'update',student_id:p.studentId,note_id:editNote.id,title,content,color:noteColor})}else{await api('student-notes',{action:'create',student_id:p.studentId,subject:subCode,grade:p.grade,chapter_number:filterCh||1,title,content,note_type:noteType,color:noteColor,source:'manual'})};snd('ok');setView('grid');setEditNote(null);setTitle('');setContent('');loadNotes()};
const deleteNote=async(id:string)=>{await api('student-notes',{action:'delete',student_id:p.studentId,note_id:id});snd('click');loadNotes()};
const pinNote=async(n:Note)=>{await api('student-notes',{action:'update',student_id:p.studentId,note_id:n.id,is_pinned:!n.is_pinned});loadNotes()};
const generateNotes=async(ch:any)=>{if(!p.studentId)return;setGenLd(true);await api('student-notes',{action:'generate',student_id:p.studentId,subject:p.subject,grade:p.grade,chapter_number:ch.chapter_number,chapter_title:ch.title});setGenLd(false);snd('badge');loadNotes()};
const openEdit=(n?:Note)=>{if(n){setEditNote(n);setTitle(n.title);setContent(n.content);setNoteColor(n.color);setNoteType(n.note_type)}else{setEditNote(null);setTitle('');setContent('');setNoteColor('#E8590C');setNoteType('manual')};setView('edit')};
const typeIcon=(t:string)=>({manual:'\u270F\uFE0F',formula:'\uD83D\uDCD0',definition:'\uD83D\uDCD6',trick:'\uD83D\uDCA1',summary:'\uD83D\uDCCB',foxy_generated:'\uD83E\uDD8A',quiz_correction:'\uD83C\uDFAF'}[t]||'\uD83D\uDCDD');
if(view==='edit')return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">{editNote?'Edit Note':'New Note'}</h1></div><button onClick={()=>{setView('grid');setEditNote(null)}} className="a-badge" style={{cursor:'pointer'}}>{'\u2715'} Cancel</button></div><div className="a-card" style={{maxWidth:640}}><input value={title} onChange={e=>setTitle(e.target.value)} placeholder="Note title..." style={{width:'100%',padding:'12px 0',border:'none',borderBottom:'2px solid #E7E5E4',fontSize:18,fontWeight:700,outline:'none',fontFamily:'inherit',background:'transparent',marginBottom:16}}/><div style={{display:'flex',gap:6,marginBottom:12,flexWrap:'wrap'}}>{[{v:'manual',l:'\u270F\uFE0F Note'},{v:'formula',l:'\uD83D\uDCD0 Formula'},{v:'definition',l:'\uD83D\uDCD6 Definition'},{v:'trick',l:'\uD83D\uDCA1 Trick'},{v:'summary',l:'\uD83D\uDCCB Summary'}].map(t=><button key={t.v} onClick={()=>setNoteType(t.v)} className={`a-pill${noteType===t.v?' on':''}`}>{t.l}</button>)}</div><div style={{display:'flex',gap:6,marginBottom:16}}>{NC.map(c=><button key={c} onClick={()=>setNoteColor(c)} style={{width:28,height:28,borderRadius:8,background:c,border:noteColor===c?'3px solid #1C1917':'2px solid transparent',cursor:'pointer'}}/>)}</div><textarea value={content} onChange={e=>setContent(e.target.value)} placeholder="Write your note..." style={{width:'100%',minHeight:200,padding:14,borderRadius:12,border:'1.5px solid #E7E5E4',fontSize:14,lineHeight:1.7,outline:'none',fontFamily:'inherit',resize:'vertical',background:'#FAFAF8'}}/><div style={{display:'flex',gap:10,marginTop:16}}><button onClick={saveNote} disabled={!title.trim()} className="a-daily-go" style={{flex:1}}>{editNote?'Update':'Save Note'}</button>{editNote&&<button onClick={()=>{deleteNote(editNote.id);setView('grid');setEditNote(null)}} style={{padding:14,borderRadius:14,border:'none',background:'#FEE2E2',color:'#DC2626',fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>{'\uD83D\uDDD1\uFE0F'}</button>}</div></div></div>);
const grouped:Record<string,Note[]>={};notes.forEach(n=>{const k=n.chapter_number?`Ch ${n.chapter_number}`:'General';if(!grouped[k])grouped[k]=[];grouped[k].push(n)});
return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Notes</h1><p className="a-greet">{p.subject} &middot; {notes.length} notes</p></div><button onClick={()=>openEdit()} className="a-add-btn">+ New Note</button></div><div style={{display:'flex',gap:6,marginBottom:16,overflowX:'auto',paddingBottom:4}}><button onClick={()=>setFilterCh(null)} className={`a-pill${!filterCh?' on':''}`}>All</button>{chs.slice(0,10).map(c=><button key={c.chapter_number} onClick={()=>{setFilterCh(c.chapter_number);snd('click')}} className={`a-pill${filterCh===c.chapter_number?' on':''}`}>Ch{c.chapter_number}</button>)}</div>{chs.length>0&&<div className="a-card" style={{padding:14,marginBottom:16,background:'linear-gradient(135deg,#1C1917,#292524)',border:'none'}}><p style={{fontSize:13,fontWeight:700,color:'#E8590C',marginBottom:8}}>{'\uD83E\uDD8A'} Foxy can generate revision notes!</p><div style={{display:'flex',gap:6,flexWrap:'wrap'}}>{chs.slice(0,6).map(c=><button key={c.chapter_number} onClick={()=>generateNotes(c)} disabled={genLd} style={{padding:'6px 12px',borderRadius:10,border:'1px solid rgba(255,255,255,.15)',background:'rgba(255,255,255,.08)',color:'rgba(255,255,255,.8)',fontSize:11,fontWeight:600,cursor:'pointer',fontFamily:'inherit'}}>Gen Ch{c.chapter_number}</button>)}</div>{genLd&&<p style={{fontSize:12,color:'#E8590C',marginTop:8}}>Generating notes...</p>}</div>}{ld?<p style={{textAlign:'center',color:'#A8A29E',padding:40}}>Loading...</p>:notes.length===0?<div style={{textAlign:'center',padding:60}}><p style={{fontSize:48}}>{'\uD83D\uDDD2\uFE0F'}</p><p style={{fontWeight:700,marginTop:12}}>No notes yet</p></div>:Object.entries(grouped).map(([group,gNotes])=>(<div key={group} style={{marginBottom:20}}><h3 style={{fontSize:13,fontWeight:800,color:'#57534E',letterSpacing:'.04em',marginBottom:10}}>{group.toUpperCase()}</h3><div className="a-notes-grid">{gNotes.map(n=>(<div key={n.id} className="a-note-card" style={{borderTop:`4px solid ${n.color}`}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:6}}><div style={{display:'flex',alignItems:'center',gap:6}}><span>{typeIcon(n.note_type)}</span><h4 style={{fontSize:14,fontWeight:700}}>{n.title}</h4></div><button onClick={()=>pinNote(n)} className="a-note-act">{n.is_pinned?'\uD83D\uDCCC':'\uD83D\uDD73\uFE0F'}</button></div><p className="a-note-body" onClick={()=>setExpanded(expanded===n.id?null:n.id)} style={{maxHeight:expanded===n.id?'none':'80px',overflow:'hidden',cursor:'pointer'}}>{n.content}</p><div style={{display:'flex',justifyContent:'space-between',marginTop:8,paddingTop:8,borderTop:'1px solid #F5F4F0'}}><span style={{fontSize:10,color:'#A8A29E'}}>{n.word_count}w &middot; {new Date(n.updated_at).toLocaleDateString('en-IN',{day:'numeric',month:'short'})}</span><button onClick={()=>openEdit(n)} style={{fontSize:11,color:'#E8590C',fontWeight:700,background:'none',border:'none',cursor:'pointer',fontFamily:'inherit'}}>Edit</button></div></div>))}</div></div>))}</div>)}
// PROGRESS
function Progress({p,stats}:{p:Prof;stats:Stats}){const[mastery,setMastery]=useState<any[]>([]);useEffect(()=>{if(p.studentId)getTopicMastery(p.studentId,SM[p.subject]||'math').then(setMastery)},[p.studentId,p.subject]);const acc=stats.asked>0?Math.round((stats.correct/stats.asked)*100):0;return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Progress</h1><p className="a-greet">{p.subject} &middot; {p.grade}</p></div></div><div className="a-stats" style={{marginBottom:20}}>{[{v:String(stats.xp),l:'XP',i:'\u26A1'},{v:String(stats.streak),l:'Streak',i:'\uD83D\uDD25'},{v:String(stats.sessions),l:'Quizzes',i:'\uD83D\uDCDA'},{v:`${acc}%`,l:'Accuracy',i:'\uD83C\uDFAF'},{v:String(stats.minutes),l:'Minutes',i:'\u23F1'},{v:String(stats.asked),l:'Questions',i:'\u2753'}].map(x=>(<div key={x.l} className="a-stat"><span style={{fontSize:18}}>{x.i}</span><p className="a-stat-v">{x.v}</p><p className="a-stat-l">{x.l}</p></div>))}</div>{mastery.length>0?<div className="a-card"><h3 className="a-card-t">SKILL MASTERY</h3>{mastery.map((t:any,i:number)=><div key={i} style={{marginBottom:12}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}><span style={{fontSize:13,fontWeight:600}}>{t.topic_tag?.replace(/_/g,' ')}</span><span style={{fontSize:12,fontWeight:700,color:t.mastery_percent>=70?'#16A34A':t.mastery_percent>=40?'#D97706':'#DC2626'}}>{t.mastery_percent}% {t.mastery_level}</span></div><div style={{height:6,borderRadius:3,background:'#F5F4F0'}}><div style={{height:'100%',borderRadius:3,width:`${t.mastery_percent}%`,background:t.mastery_percent>=70?'#16A34A':t.mastery_percent>=40?'#D97706':'#DC2626'}}/></div></div>)}</div>:<div className="a-card" style={{textAlign:'center',padding:40}}><p style={{fontSize:40}}>&#x1F4CA;</p><p style={{fontWeight:700,marginTop:8}}>No mastery data yet</p><p style={{color:'#A8A29E',fontSize:13}}>Complete a quiz to see progress!</p></div>}</div>)}
// PROFILE
function ProfileScr({p,onUp,out,stats}:{p:Prof;onUp:(p:Prof)=>void;out:()=>void;stats:Stats}){const[ed,setEd]=useState<string|null>(null);const[nm,setNm]=useState(p.name);const[gr,setGr]=useState(p.grade);const[su,setSu]=useState(p.subject);const[la,setLa]=useState(p.language);const save=()=>{snd('ok');onUp({...p,name:nm,grade:gr,subject:su,language:la});setEd(null)};const acc=stats.asked>0?Math.round((stats.correct/stats.asked)*100):0;return(<div className="a-page"><div style={{textAlign:'center',padding:'16px 0 20px'}}><div style={{width:72,height:72,borderRadius:'50%',margin:'0 auto 10px',background:'linear-gradient(135deg,#E8590C,#DC2626)',color:'#fff',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28,fontWeight:900}}>{nm.charAt(0).toUpperCase()}</div><h1 style={{fontSize:22,fontWeight:900}}>{nm}</h1><p style={{fontSize:13,color:'#A8A29E',marginTop:4}}>{gr} &middot; {su}</p><div style={{display:'flex',justifyContent:'center',gap:20,marginTop:12}}>{[{v:String(stats.xp),l:'XP'},{v:String(stats.sessions),l:'Quizzes'},{v:`${acc}%`,l:'Accuracy'}].map(x=>(<div key={x.l}><p style={{fontSize:18,fontWeight:900}}>{x.v}</p><p style={{fontSize:10,color:'#A8A29E',fontWeight:600}}>{x.l}</p></div>))}</div></div><div style={{maxWidth:520,margin:'0 auto'}}>{[{k:'name',l:'Name',v:nm},{k:'grade',l:'Grade',v:gr},{k:'subject',l:'Subject',v:su},{k:'lang',l:'Language',v:LANGS.find(l=>l.code===la)?.label||la}].map(f=><div key={f.k} className="a-card" style={{padding:0,overflow:'hidden',marginBottom:10}}><div className="a-pr" onClick={()=>{setEd(ed===f.k?null:f.k);snd('click')}}><span className="a-pr-l">{f.l}</span><span className="a-pr-v">{ed===f.k?'':f.v}</span><span style={{color:'#A8A29E'}}>{ed===f.k?'\u2715':'\u270E'}</span></div>{ed===f.k&&<div className="a-ed">{f.k==='name'&&<><input value={nm} onChange={e=>setNm(e.target.value)} className="a-ed-inp" autoFocus/><button onClick={save} disabled={!nm.trim()} className="a-ed-btn">Save</button></>}{f.k==='grade'&&<><div style={{display:'flex',gap:6,flexWrap:'wrap'}}>{GRADES.map(g=><button key={g} onClick={()=>{setGr(g);snd('click')}} className={`a-pill-n${gr===g?' on':''}`}>{g}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}{f.k==='subject'&&<><div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:6}}>{SUBJ.filter(x=>{const g=parseInt(gr.replace(/\D/g,'')||'6');return g>=11?['Mathematics','Physics','Chemistry','Biology','English','Computer Science','Accountancy','Economics'].includes(x.id):['Mathematics','Science','English','Hindi','Social Studies'].includes(x.id)}).map(x=><button key={x.id} onClick={()=>{setSu(x.id);snd('click')}} style={{padding:'7px 9px',borderRadius:10,border:su===x.id?'none':'1px solid #E7E5E4',background:su===x.id?x.c:'#fff',color:su===x.id?'#fff':'#1C1917',fontSize:11,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}><span>{x.icon}</span> {x.id}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}{f.k==='lang'&&<><div style={{display:'flex',gap:6,flexWrap:'wrap'}}>{LANGS.map(l=><button key={l.code} onClick={()=>{setLa(l.code);snd('click')}} className={`a-pill-n${la===l.code?' on':''}`}>{l.label}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}</div>}</div>)}<button onClick={()=>{snd('click');out()}} style={{width:'100%',marginTop:8,padding:12,borderRadius:14,border:'none',background:'#FEE2E2',color:'#DC2626',fontSize:13,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>Sign Out</button><p style={{textAlign:'center',fontSize:10,color:'#D4D0C8',marginTop:20}}>Alfanumrik\u00AE v4.0 &middot; CusioSense Learning India Private Limited</p></div></div>)}
// NAV
function Nav({active,nav,p}:{active:Screen;nav:(s:Screen)=>void;p:Prof}){const tabs=[{sc:'home' as Screen,l:'Today',i:'\u2299'},{sc:'foxy' as Screen,l:'Foxy',i:'\uD83E\uDD8A'},{sc:'quiz' as Screen,l:'Quiz',i:'\uD83C\uDFAF'},{sc:'notes' as Screen,l:'Notes',i:'\uD83D\uDDD2\uFE0F'},{sc:'progress' as Screen,l:'Progress',i:'\u25D4'},{sc:'profile' as Screen,l:'Profile',i:'\u25D0'}];return(<><nav className="a-side"><div className="a-side-brand"><span style={{fontSize:24}}>&#x1F98A;</span><span className="a-side-name">Alfanumrik</span></div><div className="a-side-nav">{tabs.map(t=><button key={t.sc} onClick={()=>{snd('nav');nav(t.sc)}} className={`a-side-btn${active===t.sc?' on':''}`}><span className="a-side-ic">{t.i}</span><span>{t.l}</span></button>)}</div><div className="a-side-user"><div className="a-side-av">{p.name.charAt(0)}</div><div><p style={{fontSize:13,fontWeight:700}}>{p.name}</p><p style={{fontSize:11,color:'#A8A29E'}}>{p.grade}</p></div></div></nav><nav className="a-bot">{tabs.map(t=><button key={t.sc} onClick={()=>{snd('nav');nav(t.sc)}} className={`a-bot-btn${active===t.sc?' on':''}`}><span className="a-bot-ic">{t.i}</span><span className="a-bot-lb">{t.l}</span></button>)}</nav></>)}
// MAIN APP — loads history on startup, persists everything
export default function App(){
  const[sc,setSc]=useState<Screen>('loading');const[user,setUser]=useState<any>(null);const[prof,setProf]=useState<Prof|null>(null);const[stats,setStats]=useState<Stats>({xp:0,streak:0,sessions:0,correct:0,asked:0,minutes:0});const[history,setHistory]=useState<any>(null)
  const loadAll=useCallback(async(p:Prof)=>{if(!p.studentId)return;const[s,h]=await Promise.all([getStats(p.studentId),api('chat-history',{action:'get_history',student_id:p.studentId})]);setStats(s);setHistory(h)},[])
  useEffect(()=>{if(typeof window!=='undefined'){const params=new URLSearchParams(window.location.search);if(params.get('reset')==='true'||window.location.hash.includes('type=recovery')){setSc('reset');return}}
  sb.auth.getSession().then(async({data:{session}})=>{if(session?.user){setUser(session.user);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(session.user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));await loadAll(wp);setSc('home')}else setSc('onboard')}else setSc('auth')});
  const{data:{subscription}}=sb.auth.onAuthStateChange(async(ev,s)=>{if(s?.user){setUser(s.user);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(s.user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);await loadAll(wp);setSc('home')}else setSc('onboard')}else if(sc!=='reset'&&sc!=='confirm'){setUser(null);setSc('auth')}});return()=>subscription.unsubscribe()},[loadAll])
  const onAuth=async(u:any)=>{setUser(u);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(u.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));await loadAll(wp);setSc('home')}else setSc('onboard')}
  const onOb=async(p:Prof)=>{if(user){const sid=await ensureStudent(user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));setSc('home')}}
  const onProfUp=async(p:Prof)=>{setProf(p);localStorage.setItem('alfanumrik_profile',JSON.stringify(p));if(p.studentId){await sb.from('students').update({name:p.name,grade:p.grade,preferred_language:p.language}).eq('id',p.studentId);await loadAll(p)}}
  const refreshStats=async()=>{if(prof?.studentId){const s=await getStats(prof.studentId);setStats(s);const h=await api('chat-history',{action:'get_history',student_id:prof.studentId});setHistory(h)}}
  const logout=async()=>{await sb.auth.signOut();localStorage.removeItem('alfanumrik_profile');setUser(null);setProf(null);setSc('auth')}
  if(sc==='loading')return<><CSS/><div className="a-center"><div style={{fontSize:48,animation:'pulse 1.5s infinite'}}>&#x1F98A;</div><p style={{color:'#A8A29E',marginTop:8}}>Loading...</p></div></>
  if(sc==='auth')return<><CSS/><Auth onAuth={onAuth} onConfirm={()=>setSc('confirm')}/></>
  if(sc==='confirm')return<><CSS/><ConfirmScreen onBack={()=>setSc('auth')}/></>
  if(sc==='reset')return<><CSS/><ResetScreen/></>
  if(sc==='onboard')return<><CSS/><Onboard user={user} done={onOb}/></>
  return(<><CSS/><div className="a-shell">{prof&&<Nav active={sc} nav={setSc} p={prof}/>}<main className="a-main">{sc==='home'&&prof&&<Home p={prof} nav={setSc} stats={stats} history={history}/>}{sc==='foxy'&&prof&&<Foxy p={prof}/>}{sc==='quiz'&&prof&&<Quiz p={prof} onDone={refreshStats}/>}{sc==='notes'&&prof&&<Notes p={prof}/>}{sc==='progress'&&prof&&<Progress p={prof} stats={stats}/>}{sc==='profile'&&prof&&<ProfileScr p={prof} onUp={onProfUp} out={logout} stats={stats}/>}</main></div></>)
}
